// Собираем данные из всех предыдущих нод
const nodes = $('Get Nodes').first().json.items || [];
const pods = $('Get All Pods').first().json.items || [];
const pvcs = $('Get PVCs').first().json.items || [];
const backups = $('Get Backups').first().json.items || [];

const now = new Date();
const dateStr = now.toLocaleDateString('uk-UA', { timeZone: 'Europe/Kiev', day: '2-digit', month: '2-digit', year: 'numeric' });
const timeStr = now.toLocaleTimeString('uk-UA', { timeZone: 'Europe/Kiev', hour: '2-digit', minute: '2-digit' });

// Ноды
const nodesReady = nodes.filter(n => n.status.conditions?.find(c => c.type === 'Ready' && c.status === 'True')).length;
let nodesSection = `🖥️ <b>Nodes:</b> ${nodesReady}/${nodes.length} Ready`;
if (nodesReady < nodes.length) {
  const notReady = nodes.filter(n => !n.status.conditions?.find(c => c.type === 'Ready' && c.status === 'True'));
  nodesSection += `\n⚠️ Not ready: ${notReady.map(n => n.metadata.name).join(', ')}`;
}

// Поды по фазам
const podsByPhase = {};
for (const pod of pods) {
  const phase = pod.status.phase || 'Unknown';
  podsByPhase[phase] = (podsByPhase[phase] || 0) + 1;
}
const problemPods = pods.filter(p => {
  const phase = p.status.phase;
  if (phase === 'Running') {
    return (p.status.containerStatuses || []).some(c => c.restartCount > 5);
  }
  return phase !== 'Running' && phase !== 'Succeeded';
});
let podsSection = `📦 <b>Pods:</b> ${pods.length} total\n`;
podsSection += `   ✅ Running: ${podsByPhase['Running'] || 0} | ⏳ Pending: ${podsByPhase['Pending'] || 0} | ❌ Failed: ${podsByPhase['Failed'] || 0}`;
if (problemPods.length > 0) {
  podsSection += `\n⚠️ High restarts (>5): ${problemPods.length} pods`;
  for (const pod of problemPods.slice(0, 3)) {
    const restarts = (pod.status.containerStatuses || []).reduce((s, c) => s + c.restartCount, 0);
    podsSection += `\n   🔴 ${pod.metadata.namespace}/${pod.metadata.name} (${restarts} restarts)`;
  }
}

// PVC
const pvcsOk = pvcs.filter(p => p.status.phase === 'Bound').length;
const pvcsFail = pvcs.filter(p => p.status.phase !== 'Bound').length;
const totalGi = pvcs.reduce((sum, p) => {
  const q = p.spec.resources?.requests?.storage || '0';
  return sum + parseInt(q);
}, 0);
let pvcsSection = `💾 <b>PVCs:</b> ${pvcsOk} Bound`;
if (pvcsFail > 0) pvcsSection += ` | ⚠️ ${pvcsFail} not Bound`;

// Velero backups (последние 3)
const recentBackups = backups
  .sort((a, b) => new Date(b.metadata.creationTimestamp) - new Date(a.metadata.creationTimestamp))
  .slice(0, 3);
let backupSection = '🔒 <b>Velero Backups (last 3):</b>\n';
if (recentBackups.length === 0) {
  backupSection += '   ⚠️ No backups found';
} else {
  for (const bk of recentBackups) {
    const phase = bk.status?.phase || 'Unknown';
    const emoji = phase === 'Completed' ? '✅' : phase === 'Failed' ? '❌' : '⏳';
    const name = bk.metadata.name;
    const ts = new Date(bk.metadata.creationTimestamp).toLocaleDateString('uk-UA', { day: '2-digit', month: '2-digit' });
    backupSection += `   ${emoji} ${name} (${ts})\n`;
  }
}

// Итоговое сообщение
const clusterOk = nodesReady === nodes.length && problemPods.length === 0 && pvcsFail === 0;
const headerEmoji = clusterOk ? '✅' : '⚠️';

let message = `${headerEmoji} <b>DevOps Lab — Daily Report</b>\n`;
message += `📅 ${dateStr} ${timeStr} (Kyiv)\n`;
message += `\n${nodesSection}\n`;
message += `\n${podsSection}\n`;
message += `\n${pvcsSection}\n`;
message += `\n${backupSection}`;
message += `\n🔗 <a href="https://argocd.lab.local">Argo CD</a> | <a href="https://grafana.lab.local">Grafana</a> | <a href="https://kuma.lab.local">Uptime Kuma</a>`;

return [{ json: { message } }];
